import React from 'react';

const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {
  
  // Helper to turn the numeric EPA index into readable text
  const getAQIDesc = (index) => {
    const levels = {
      1: { text: "Good", color: "#4caf50" },
      2: { text: "Moderate", color: "#ffeb3b" },
      3: { text: "Unhealthy for Sensitive Groups", color: "#ff9800" },
      4: { text: "Unhealthy", color: "#f44336" },
      5: { text: "Very Unhealthy", color: "#9c27b0" },
      6: { text: "Hazardous", color: "#7e0023" }
    };
    return levels[index] || { text: "Unknown", color: "#9e9e9e" };
  };

  const aqiInfo = getAQIDesc(aqi);

  return (
    <div className="card">
      <div className="card-header">
        <h2>{city}</h2>
        <div className="condition-tag">{condition}</div>
      </div>

      <div className="main-weather">
        <img src={icon} alt={condition} className="weather-icon" />
        <div className="temp">{Math.round(temperature)}°C</div>
      </div>

      <div className="stats">
        <div className="stat-box">
          <span className="label">Feels Like</span>
          <div className="value">🌡️ {feelsLike}°C</div>
        </div>
        <div className="stat-box">
          <span className="label">Wind</span>
          <div className="value">💨 {wind} km/h</div>
        </div>
        <div className="stat-box">
          <span className="label">Humidity</span>
          <div className="value">💧 {humidity}%</div>
        </div>
      </div>

      {aqi && (
        <div 
          className="aqi-badge" 
          style={{ backgroundColor: aqiInfo.color, color: aqiInfo.text === "Moderate" ? "#000" : "#fff" }}
        >
          AQI: {aqiInfo.text}
        </div>
      )}
    </div>
  );
};

export default WeatherCard;
